int main() {
    Vector2D v1(1.0, 2.0);
    Vector2D v2(3.0, 4.0);
    std::cout << "Before addition:" << std::endl;
    std::cout << "Vector v1: "; v1.print(); std::cout << std::endl;
    std::cout << "Vector v2: "; v2.print(); std::cout << std::endl;
    Vector2D v3 = v1 + v2;
    std::cout << "After addition:" << std::endl;
    std::cout << "Vector v1: "; v1.print(); std::cout << std::endl;
    std::cout << "Vector v2: "; v2.print(); std::cout << std::endl;
    std::cout << "v1 + v2 (v3) = "; v3.print(); std::cout << std::endl;
    Vector2D v4(10.0, 10.0);
    Vector2D v5(1.0, 1.0);
    Vector2D v6(2.0, 2.0);
    Vector2D v7 = (v4 + v5) + v6;
    std::cout << "Chained addition (v4 + v5) + v6 = "; v7.print(); std::cout << std::endl;
    std::cout << "Original v4 after chained addition: "; v4.print(); std::cout << std::endl;
    return 0;
}
